import com.caucho.hessian.io.HessianProtocolException;
import com.caucho.hessian.io.SerializerFactory;
import java.io.ByteArrayInputStream;
import java.io.IOException;

/**
 * Hessian2 Deserialization Service
 * Provides deserialization functionality for Hessian2-formatted data
 */
public class HessianService {

    // Thread-safe serializer factory with class whitelist, reused for all deserialization operations
    private static final SerializerFactory SAFE_SERIALIZER_FACTORY;

    static {
        SAFE_SERIALIZER_FACTORY = new SerializerFactory() {
            @Override
            public Deserializer getDeserializer(Class cl) throws HessianProtocolException {
                // Recursively check component type for array classes
                Class<?> checkClz = cl;
                while (checkClz.isArray()) {
                    checkClz = checkClz.getComponentType();
                }

                // Allow primitive types, their wrapper classes, and common immutable value types
                boolean allowed = checkClz.isPrimitive()
                        || checkClz == String.class
                        || checkClz == Boolean.class
                        || checkClz == Byte.class
                        || checkClz == Character.class
                        || checkClz == Short.class
                        || checkClz == Integer.class
                        || checkClz == Long.class
                        || checkClz == Float.class
                        || checkClz == Double.class
                        || checkClz == java.math.BigDecimal.class
                        || checkClz == java.math.BigInteger.class
                        || checkClz == java.util.Date.class
                        || checkClz == java.time.LocalDate.class
                        || checkClz == java.time.LocalDateTime.class
                        || checkClz == java.time.LocalTime.class
                        || checkClz == java.time.ZonedDateTime.class
                        // Allow standard Java collection classes (safe as long as their elements are in the whitelist)
                        || checkClz == java.util.ArrayList.class
                        || checkClz == java.util.LinkedList.class
                        || checkClz == java.util.HashMap.class
                        || checkClz == java.util.LinkedHashMap.class
                        || checkClz == java.util.HashSet.class
                        || checkClz == java.util.LinkedHashSet.class
                        || checkClz == java.util.TreeMap.class
                        || checkClz == java.util.TreeSet.class
                        || checkClz == java.util.Collections.EMPTY_LIST.getClass()
                        || checkClz == java.util.Collections.EMPTY_MAP.getClass()
                        || checkClz == java.util.Collections.EMPTY_SET.getClass();

                // TODO: Add your application's specific allowed model classes here
                // Example:
                // allowed = allowed || "com.example.model.User".equals(checkClz.getName())
                //         || "com.example.model.Order".equals(checkClz.getName())
                //         || "com.example.model.Product".equals(checkClz.getName());

                // Deny all other classes by default
                if (!allowed) {
                    throw new HessianProtocolException("Deserialization of class " + checkClz.getName() + " is not allowed.");
                }

                return super.getDeserializer(cl);
            }
        };

        // Optional: Disable deserialization of non-serializable classes if your use case does not require it
        // SAFE_SERIALIZER_FACTORY.setAllowNonSerializable(false);
    }

    /**
     * Deserializes user data
     * Accepts a byte array provided by the user and performs deserialization using Hessian2Input
     *
     * @param serializedData The serialized byte array data
     * @return The deserialized object
     * @throws IOException Thrown when an IO exception occurs during deserialization
     */
    public Object deserializeUserData(byte[] serializedData) throws IOException {
        if (serializedData == null || serializedData.length == 0) {
            throw new IllegalArgumentException("Serialized data cannot be empty");
        }

        Hessian2Input hessianInput = null;
        // Use try-with-resources for ByteArrayInputStream (implements AutoCloseable)
        try (ByteArrayInputStream bis = new ByteArrayInputStream(serializedData)) {
            hessianInput = new Hessian2Input(bis);

            // Apply the secure serializer factory with class whitelist validation
            hessianInput.setSerializerFactory(SAFE_SERIALIZER_FACTORY);

            // Perform deserialization (only whitelisted classes will be allowed)
            return hessianInput.readObject();
        } catch (Exception e) {
            throw new IOException("Deserialization failed: " + e.getMessage(), e);
        } finally {
            // Manually close Hessian2Input as it does not implement AutoCloseable
            if (hessianInput!= null) {
                try {
                    hessianInput.close();
                } catch (IOException e) {
                    // Ignore close exceptions for in-memory stream
                }
            }
        }
    }
}

